/**
 * Worktree Hook Loading Validation (CC 2.1.78, Issue #1109)
 *
 * CC 2.1.78 fixed: --worktree flag not loading skills and hooks from the
 * worktree directory. These tests validate that our worktree hooks correctly
 * handle WorktreeCreate and WorktreeRemove inputs, and that the hooks.json
 * registers both events with the correct hook.
 *
 * The CC bug was about the --worktree CLI flag; we validate from the hook
 * handler side (correct inputs → correct outputs) since we can't invoke
 * the CC runtime in unit tests.
 */

import { describe, it, expect, vi, beforeEach, beforeAll } from 'vitest';
import type { HookInput } from '../../types.js';

// Mock fs operations to avoid real filesystem reads
vi.mock('node:fs', () => ({
  readdirSync: vi.fn(() => []),
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => '{}'),
}));

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    logHook: vi.fn(),
    getProjectDir: vi.fn(() => '/test/project'),
  };
});

import { worktreeLifecycleLogger } from '../../worktree/worktree-lifecycle-logger.js';

// Also validate hooks.json registration — use actual fs (not mocked) to read hooks.json
import { resolve } from 'node:path';
import { createTestContext } from '../fixtures/test-context.js';

// eslint-disable-next-line @typescript-eslint/no-explicit-any
let hooksJson: any;

let testCtx: ReturnType<typeof createTestContext>;
describe('Worktree Hook Loading (CC 2.1.78 fix validation)', () => {
  beforeAll(async () => {
    const actualFs = await vi.importActual<typeof import('node:fs')>('node:fs');
    hooksJson = JSON.parse(actualFs.readFileSync(resolve(__dirname, '..', '..', '..', 'hooks.json'), 'utf-8'));
  });
  beforeEach(() => {
    testCtx = createTestContext();
    vi.clearAllMocks();
  });

  // ===========================================================================
  // SECTION 1: hooks.json registration
  // ===========================================================================
  describe('hooks.json registration', () => {
    it('should register WorktreeCreate event', () => {
      expect(hooksJson.hooks.WorktreeCreate).toBeDefined();
      expect(Array.isArray(hooksJson.hooks.WorktreeCreate)).toBe(true);
      expect(hooksJson.hooks.WorktreeCreate.length).toBeGreaterThan(0);
    });

    it('should register WorktreeRemove event', () => {
      expect(hooksJson.hooks.WorktreeRemove).toBeDefined();
      expect(Array.isArray(hooksJson.hooks.WorktreeRemove)).toBe(true);
      expect(hooksJson.hooks.WorktreeRemove.length).toBeGreaterThan(0);
    });

    it('should use worktree-lifecycle-logger for WorktreeCreate', () => {
      const hooks = hooksJson.hooks.WorktreeCreate.flatMap((g: Record<string, unknown>) => (g.hooks as unknown[]) ?? []);
      const hasLogger = hooks.some((h: Record<string, unknown>) =>
        typeof h.command === 'string' && h.command.includes('worktree-lifecycle-logger')
      );
      expect(hasLogger).toBe(true);
    });

    it('should use worktree-lifecycle-logger for WorktreeRemove', () => {
      const hooks = hooksJson.hooks.WorktreeRemove.flatMap((g: Record<string, unknown>) => (g.hooks as unknown[]) ?? []);
      const hasLogger = hooks.some((h: Record<string, unknown>) =>
        typeof h.command === 'string' && h.command.includes('worktree-lifecycle-logger')
      );
      expect(hasLogger).toBe(true);
    });
  });

  // ===========================================================================
  // SECTION 2: WorktreeCreate input handling
  // ===========================================================================
  describe('WorktreeCreate input handling', () => {
    it('should handle WorktreeCreate with name field', () => {
      const input: HookInput = {
        hook_event: 'WorktreeCreate',
        tool_name: '',
        session_id: 'test-session-001',
        tool_input: {},
        name: 'feature-auth',
        project_dir: '/test/project',
      };

      const result = worktreeLifecycleLogger(input);
      expect(result.continue).toBe(true);
    });

    it('should inject advisory context for WorktreeCreate', () => {
      const input: HookInput = {
        hook_event: 'WorktreeCreate',
        tool_name: '',
        session_id: 'test-session-001',
        tool_input: {},
        name: 'feat-payments',
        project_dir: '/test/project',
      };

      const result = worktreeLifecycleLogger(input);
      // Should produce context (not silent success) for WorktreeCreate
      const context = result.hookSpecificOutput?.additionalContext as string | undefined;
      expect(context).toBeDefined();
      expect(context).toContain('feat-payments');
      expect(context).toContain('WorktreeCreate');
    });

    it('should handle missing name field gracefully', () => {
      const input: HookInput = {
        hook_event: 'WorktreeCreate',
        tool_name: '',
        session_id: 'test-session-001',
        tool_input: {},
        project_dir: '/test/project',
        // name is intentionally omitted
      };

      const result = worktreeLifecycleLogger(input);
      expect(result.continue).toBe(true);
      const context = result.hookSpecificOutput?.additionalContext as string | undefined;
      expect(context).toContain('unknown');
    });
  });

  // ===========================================================================
  // SECTION 3: WorktreeRemove input handling
  // ===========================================================================
  describe('WorktreeRemove input handling', () => {
    it('should handle WorktreeRemove with worktree_path field', () => {
      const input: HookInput = {
        hook_event: 'WorktreeRemove',
        tool_name: '',
        session_id: 'test-session-001',
        tool_input: {},
        worktree_path: '/Users/dev/.git/worktrees/feat-payments',
        project_dir: '/test/project',
      };

      const result = worktreeLifecycleLogger(input);
      expect(result.continue).toBe(true);
    });

    it('should inject removal advisory for WorktreeRemove', () => {
      const input: HookInput = {
        hook_event: 'WorktreeRemove',
        tool_name: '',
        session_id: 'test-session-001',
        tool_input: {},
        worktree_path: '/Users/dev/.git/worktrees/feat-payments',
        project_dir: '/test/project',
      };

      const result = worktreeLifecycleLogger(input);
      const context = result.hookSpecificOutput?.additionalContext as string | undefined;
      expect(context).toBeDefined();
      expect(context).toContain('WorktreeRemove');
      expect(context).toContain('feat-payments');
    });

    it('should handle missing worktree_path gracefully', () => {
      const input: HookInput = {
        hook_event: 'WorktreeRemove',
        tool_name: '',
        session_id: 'test-session-001',
        tool_input: {},
        // worktree_path intentionally omitted
      };

      const result = worktreeLifecycleLogger(input);
      expect(result.continue).toBe(true);
    });
  });

  // ===========================================================================
  // SECTION 4: Unexpected event handling
  // ===========================================================================
  describe('Unexpected event handling', () => {
    it('should return silent success for unrecognised events', () => {
      const input: HookInput = {
        hook_event: 'Stop', // wrong event routed here
        tool_name: '',
        session_id: 'test-session-001',
        tool_input: {},
      };

      const result = worktreeLifecycleLogger(input);
      expect(result).toEqual({ continue: true, suppressOutput: true });
    });
  });
});
